import React from "react";
import { motion } from "framer-motion";

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;

  const [firstName, ...rest] = name.split(" ");
  const lastName = rest.join(" ");

  return (
    <>
      <style>{`
        * {
          box-sizing: border-box;
        }

        body {
          margin: 0;
          overflow-x: hidden;
          background: #05070d;
          color: white;
          font-family: sans-serif;
        }

        .hero {
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: clamp(60px, 8vw, 120px) 20px;
        }

        .container {
          width: 100%;
          max-width: min(1400px, 92vw);
          margin: auto;
        }

        /* NAME */
        .name {
          font-size: clamp(2rem, 6vw, 6rem);
          font-weight: 800;
          line-height: 1.1;
          text-align: center;
          word-break: break-word;
        }

        .gradient {
          background: linear-gradient(90deg, #00e5ff, #7c3aed);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }

        /* TEXT */
        .sub {
          margin-top: 12px;
          color: #aaa;
          text-align: center;
        }

        .highlight {
          color: #00e5ff;
        }

        .tag {
          margin-top: 10px;
          color: #888;
          max-width: 650px;
          margin-left: auto;
          margin-right: auto;
          text-align: center;
        }

        /* BUTTONS */
        .btns {
          display: flex;
          flex-direction: column;
          gap: 12px;
          margin-top: 25px;
          width: 100%;
        }

        .btn {
          display: flex;
          align-items: center;
          justify-content: center;   /* 🔥 MAIN FIX */
          text-align: center;
          width: 100%;
          padding: 14px 20px;
          border-radius: 999px;
          font-weight: 600;
          text-decoration: none;
          transition: all 0.3s ease;
        }

        .primary {
          background: #00e5ff;
          color: black;
        }

        .primary:hover {
          transform: translateY(-3px);
          box-shadow: 0 10px 30px rgba(0,229,255,0.3);
        }

        .outline {
          border: 1px solid #444;
          color: white;
        }

        .outline:hover {
          border-color: #00e5ff;
          color: #00e5ff;
        }

        /* DESKTOP */
        @media (min-width: 768px) {
          .name,
          .sub,
          .tag {
            text-align: left;
          }

          .btns {
            flex-direction: row;
            justify-content: flex-start;
          }

          .btn {
            width: auto;
            min-width: 180px;
          }
        }

        /* STATS */
        .stats {
          margin-top: 50px;
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
          gap: 20px;
        }

        .card {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          text-align: center;
          padding: 25px;
          border-radius: 16px;
          background: rgba(255,255,255,0.05);
          border: 1px solid rgba(255,255,255,0.08);
          transition: 0.3s;
        }

        .card:hover {
          transform: translateY(-6px) scale(1.03);
          box-shadow: 0 20px 50px rgba(0,229,255,0.15);
        }

        .value {
          font-size: clamp(1.5rem, 2.5vw, 3rem);
          font-weight: 800;
          color: #00e5ff;
        }

        .label {
          margin-top: 8px;
          color: #aaa;
        }
      `}</style>

      <section className="hero">
        <div className="container">

          {/* NAME */}
          <motion.h1
            className="name"
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
          >
            {firstName} <span className="gradient">{lastName}</span>
          </motion.h1>

          {/* SUBTITLE */}
          <motion.p
            className="sub"
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
            {title} · <span className="highlight">{subtitle}</span>
          </motion.p>

          {/* TAGLINE */}
          <motion.p
            className="tag"
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
          >
            {tagline}
          </motion.p>

          {/* BUTTONS */}
          <motion.div
            className="btns"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.6 }}
          >
            <motion.a
              href="mailto:your@email.com"
              className="btn primary"
              whileHover={{ scale: 1.05 }}
            >
              Get in Touch
            </motion.a>

            <motion.a
              href={`https://${contact.linkedin}`}
              target="_blank"
              className="btn outline"
              whileHover={{ scale: 1.05 }}
            >
              LinkedIn
            </motion.a>
          </motion.div>

          {/* STATS */}
          <div className="stats">
            {stats.map((s, i) => (
              <motion.div
                key={i}
                className="card"
                initial={{ opacity: 0, y: 40 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.8 + i * 0.1 }}
                whileHover={{ scale: 1.05 }}
              >
                <div className="value">{s.value}</div>
                <div className="label">{s.label}</div>
              </motion.div>
            ))}
          </div>

        </div>
      </section>
    </>
  );
}
